import anthropic
import json

client = anthropic.Anthropic()

def resolve_conflict_by_confidence(
    output_a: dict, output_b: dict
) -> dict:
    """
    Choose the higher-confidence output.
    If confidence is equal, merge findings from both.
    Both outputs must have 'findings' (list) and 'confidence' (float).
    """
    conf_a = output_a.get("confidence", 0.0)
    conf_b = output_b.get("confidence", 0.0)

    if abs(conf_a - conf_b) < 0.05:
        # Too close to call — merge findings, lower confidence
        merged_findings = list({f for f in output_a.get("findings", []) + output_b.get("findings", [])})
        return {
            "findings": merged_findings,
            "confidence": (conf_a + conf_b) / 2,
            "resolution": "merged (confidence tie)",
        }
    elif conf_a > conf_b:
        return {**output_a, "resolution": f"used output_a (conf {conf_a:.2f} > {conf_b:.2f})"}
    else:
        return {**output_b, "resolution": f"used output_b (conf {conf_b:.2f} > {conf_a:.2f})"}

def resolve_conflict_adversarial(output_a: dict, output_b: dict, question: str) -> dict:
    """
    Use a synthesis agent to reconcile conflicting outputs.
    Used when neither output is clearly more reliable.
    """
    prompt = (
        f"Two research agents answered the same question: '{question}'\n\n"
        f"Agent A findings: {json.dumps(output_a.get('findings', []))}\n"
        f"Agent B findings: {json.dumps(output_b.get('findings', []))}\n\n"
        "These findings conflict. Produce a single reconciled answer that:"
        " 1) includes claims both agents agree on,"
        " 2) flags genuine contradictions as unresolved,"
        " 3) omits claims only one agent makes if not independently verifiable.\n"
        'Return JSON: {"reconciled": [...], "unresolved": [...], "confidence": 0.0-1.0}'
    )
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        messages=[{"role": "user", "content": prompt}],
    )
    text = resp.content[0].text.strip()
    if text.startswith("```"):
        lines = text.split("\n")
        text = "\n".join(lines[1:-1] if lines[-1].strip() == "```" else lines[1:])
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        return {"reconciled": [], "unresolved": [], "confidence": 0.0}

# Example: two researchers gave different answers
r1_output = {
    "findings": ["Tokyo population: 13.96 million (2020 census)"],
    "confidence": 0.9,
}
r2_output = {
    "findings": ["Tokyo population: approximately 14 million"],
    "confidence": 0.85,
}
result = resolve_conflict_by_confidence(r1_output, r2_output)
print(result["resolution"])
# "used output_a (conf 0.90 > 0.85)"
